//! Spec-compliance tests: MS-OI29500 Sections (§17.6), Numbering (§17.9),
//! Document Settings (§17.15), and MS-DOCX CompatSettings (§2.3).
//!
//! These tests verify our implementation against Microsoft's implementation
//! notes and extensions to the OOXML standard.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/ms-sections-settings";

// -- helpers ----------------------------------------------------------------
/// Collect all paragraphs that have structured section properties.
fn section_paragraphs(doc: &CanonDoc) -> Vec<&stemma::SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(
    blocks: &'a [BlockNode],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

