/// MS-DOCX §2.3.5: compatibilityMode determines the feature set.
///
/// The document has compatibilityMode=15 in w:compat/w:compatSetting.
/// Our settings parser exposes this value so the renderer can branch on it.
#[test]
fn ms_compat_mode_15_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "compat-mode-15");

    assert_eq!(
        doc.compat_settings.compatibility_mode,
        Some(15),
        "compatibilityMode should be 15 (Word 2013+ features)"
    );
}

