// ==========================================================================
// SECTION PROPERTIES (MS-OI29500 §17.6)
// ==========================================================================

/// MS-OI29500 §17.6.3/§17.6.4: Column definitions with unequal widths.
///
/// Word defaults equalWidth to true. When equalWidth=false, individual
/// col elements specify widths. Missing space attr on col defaults to 0.
/// Also: num must match child col count when equalWidth=false.
#[test]
fn ms_section_cols_unequal_widths() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "section-cols-unequal");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    assert_eq!(props.columns, Some(3), "should parse num=3 from w:cols");

    // Individual column definitions from w:col children
    assert_eq!(
        props.column_defs.len(),
        3,
        "should have 3 column definitions"
    );
    // Column 0: w=3000, space=360
    assert_eq!(props.column_defs[0].width, 3000);
    assert_eq!(props.column_defs[0].space, 360);
    // Column 1: w=4000, space=360
    assert_eq!(props.column_defs[1].width, 4000);
    assert_eq!(props.column_defs[1].space, 360);
    // Column 2: w=3000, space=0 (default per MS §17.6.3)
    assert_eq!(props.column_defs[2].width, 3000);
    assert_eq!(props.column_defs[2].space, 0);
}

/// MS-OI29500 §17.6.10: pgBorders default zOrder=front, offsetFrom=text.
///
/// When the zOrder and offsetFrom attributes are omitted from w:pgBorders,
/// Word defaults them to 'front' and 'text' respectively.
#[test]
fn ms_pg_borders_default_z_order_and_offset() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "pg-borders-defaults");

    let section_props = section_paragraphs(&doc);
    assert!(!section_props.is_empty(), "should have section properties");

    let props = section_props[0];
    let borders = props
        .page_borders
        .as_ref()
        .expect("should have page borders");

    // Verify border styles are parsed
    let top = borders.top.as_ref().expect("should have top border");
    assert_eq!(top.style, stemma::domain::BorderStyle::Single);
    assert_eq!(top.color.as_deref(), Some("FF0000"));

    // MS-OI29500 §17.6.10: defaults when omitted
    assert_eq!(
        borders.z_order.as_str(),
        "front",
        "zOrder should default to 'front'"
    );
    assert_eq!(
        borders.offset_from.as_str(),
        "text",
        "offsetFrom should default to 'text'"
    );
}

/// MS-OI29500 §17.6.8b: Word uses lnNumType start as skip count.
///
/// The standard says start=3 means numbering starts at 3. But Word
/// uses start as a skip count: start=3 means skip 3, start at 4.
///
/// FIXED: display_start() provides the MS-compatible rendering value.
#[test]
fn ms_line_numbering_start_as_skip_count() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "ln-num-start-skip");

    let section_props = section_paragraphs(&doc);
    assert!(!section_props.is_empty(), "should have section properties");

    let props = section_props[0];
    let ln = props
        .line_numbering
        .as_ref()
        .expect("should have line numbering");

    // Raw value preserved for round-tripping
    assert_eq!(ln.start, Some(3));
    assert_eq!(ln.count_by, Some(1));

    // MS-compatible rendering: start=3 means skip 3, display begins at 4.
    assert_eq!(
        ln.display_start(),
        4,
        "display_start() should return start+1 for MS-compatible rendering"
    );
}

/// MS-OI29500 §17.6.22: Section type val attribute is required by Word.
///
/// The standard implies val is optional, but Word requires it. This test
/// verifies we parse an explicit val correctly.
#[test]
fn ms_section_type_val_required() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "section-type-val-required");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one section"
    );

    assert_eq!(
        section_props[0].section_type,
        Some(stemma::domain::SectionType::NextPage),
        "section type val=nextPage should be parsed"
    );
}

/// MS-OI29500 §17.6.18c: Word does not allow sectPr in table cells.
///
/// If a sectPr appears inside a paragraph within a table, Word ignores it.
/// Our parser should either ignore it or at minimum not crash.
///
/// FIXED: sectPr in table cell paragraphs is now stripped.
#[test]
fn ms_sect_pr_not_allowed_in_tables() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "sect-pr-in-table");

    // sectPr should NOT appear on any paragraph inside a table
    for tracked in &doc.blocks {
        if let BlockNode::Table(t) = &tracked.block {
            for row in &t.rows {
                for cell in &row.cells {
                    for block in &cell.blocks {
                        if let BlockNode::Paragraph(p) = block {
                            assert!(
                                p.section_properties.is_none(),
                                "sectPr should not be parsed from table cell paragraphs \
                                 (MS-OI29500 §17.6.18c)"
                            );
                        }
                    }
                }
            }
        }
    }

    // If we get here without panic, the test passes (no sectPr in tables)
}

// ==========================================================================
// NUMBERING EDGE CASES (MS-OI29500 §17.9)
// ==========================================================================

/// MS-OI29500 §17.9.4a: isLgl affects ALL levels including current.
///
/// The standard implies only previous levels are affected by isLgl.
/// Word applies isLgl to ALL numbering levels, including the immediate one.
///
/// Our implementation currently preserves the current level's format while
/// forcing other levels to decimal. Per MS behavior, ALL levels should be
/// forced to decimal when isLgl is set.
///
/// FIXED: Current level's format is now also forced to decimal with isLgl.
#[test]
fn ms_is_lgl_affects_all_levels_including_current() {
    // This is a unit test against the numbering engine, not a fixture test.
    // We build the numbering definitions inline.
    use stemma::numbering::{NumberingDefinitions, NumberingState};

    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="upperRoman"/>
      <w:lvlText w:val="%1"/>
    </w:lvl>
    <w:lvl w:ilvl="1">
      <w:start w:val="1"/>
      <w:numFmt w:val="lowerLetter"/>
      <w:isLgl/>
      <w:lvlText w:val="%1.%2"/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = NumberingDefinitions::parse(xml.as_bytes()).unwrap();
    let mut state = NumberingState::new();

    // Level 0: "I" (upperRoman, no isLgl)
    assert_eq!(state.synthesize(&defs, 1, 0).unwrap(), "I");

    // Level 1 has isLgl. Per MS behavior, BOTH %1 and %2 should be
    // formatted as decimal (including %2, the current level).
    //
    // Current behavior: %1 → decimal "1", %2 → lowerLetter "a" → "1.a"
    // Expected (MS): %1 → decimal "1", %2 → decimal "1" → "1.1"
    let result = state.synthesize(&defs, 1, 1).unwrap();
    assert_eq!(
        result, "1.1",
        "isLgl should force ALL levels to decimal (MS §17.9.4a), \
         including the current level. Got '{result}' but expected '1.1'"
    );
}

/// MS-OI29500 §17.9.4b: isLgl with numFmt=none — none format is preserved.
///
/// When the actual numbering format of a level is 'none', Word displays
/// it as 'none' regardless of isLgl.
#[test]
fn ms_is_lgl_preserves_none_format() {
    use stemma::numbering::{NumberingDefinitions, NumberingState};

    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="none"/>
      <w:lvlText w:val=""/>
    </w:lvl>
    <w:lvl w:ilvl="1">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:isLgl/>
      <w:lvlText w:val="%1.%2"/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = NumberingDefinitions::parse(xml.as_bytes()).unwrap();
    let mut state = NumberingState::new();

    // Level 0 is 'none' — produces empty string
    assert_eq!(state.synthesize(&defs, 1, 0).unwrap(), "");

    // Level 1 has isLgl. Per MS behavior, %1 references level 0 which is
    // 'none', and 'none' is preserved even with isLgl. So %1 should produce
    // empty string, and the result should be ".1" (empty + "." + "1").
    let result = state.synthesize(&defs, 1, 1).unwrap();
    assert_eq!(
        result, ".1",
        "isLgl should preserve 'none' format (MS §17.9.4b). Got '{result}'"
    );
}

/// MS-OI29500 §17.9.10c/d: lvlRestart triggers on specified level
/// AND any higher (shallower) level.
///
/// The standard says "restarts when the specified level is used", but
/// Word restarts when the specified level OR any higher level is used.
/// Our implementation already handles this — this test confirms it.
#[test]
fn ms_lvl_restart_triggers_on_higher_levels() {
    use stemma::numbering::{NumberingDefinitions, NumberingState};

    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%1."/>
    </w:lvl>
    <w:lvl w:ilvl="1">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%1.%2."/>
    </w:lvl>
    <w:lvl w:ilvl="2">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlRestart w:val="2"/>
      <w:lvlText w:val="%1.%2.%3."/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = NumberingDefinitions::parse(xml.as_bytes()).unwrap();
    let mut state = NumberingState::new();

    // Build up: 1. -> 1.1. -> 1.1.1. -> 1.1.2.
    assert_eq!(state.synthesize(&defs, 1, 0).unwrap(), "1.");
    assert_eq!(state.synthesize(&defs, 1, 1).unwrap(), "1.1.");
    assert_eq!(state.synthesize(&defs, 1, 2).unwrap(), "1.1.1.");
    assert_eq!(state.synthesize(&defs, 1, 2).unwrap(), "1.1.2.");

    // lvlRestart=2 means restart when level 1 (0-indexed) is encountered.
    // Hit level 1 → level 2 should restart
    assert_eq!(state.synthesize(&defs, 1, 1).unwrap(), "1.2.");
    assert_eq!(state.synthesize(&defs, 1, 2).unwrap(), "1.2.1."); // restarted

    // Per MS §17.9.10c: hitting level 0 (higher than level 1) should ALSO
    // trigger restart of level 2
    assert_eq!(state.synthesize(&defs, 1, 0).unwrap(), "2.");
    assert_eq!(state.synthesize(&defs, 1, 1).unwrap(), "2.1.");
    assert_eq!(state.synthesize(&defs, 1, 2).unwrap(), "2.1.1."); // restarted by level 0
}

/// MS-OI29500 §17.9.17a: Bullet format uses literal lvlText, ignoring %x.
///
/// When numFmt=bullet, %1 in lvlText should NOT be replaced — it should
/// be displayed literally. Our implementation currently returns a bullet
/// character for all bullet formats.
///
/// PASS: Our bullet handling returns lvlText as-is for non-PUA characters.
#[test]
fn ms_bullet_uses_literal_lvltext() {
    use stemma::numbering::{NumberingDefinitions, NumberingState};

    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="bullet"/>
      <w:lvlText w:val="%1."/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = NumberingDefinitions::parse(xml.as_bytes()).unwrap();
    let mut state = NumberingState::new();

    // Per MS §17.9.17a: when numFmt=bullet, lvlText="%1." should be
    // displayed as the literal string "%1.", NOT as "1." or "•".
    let result = state.synthesize(&defs, 1, 0).unwrap();
    assert_eq!(
        result, "%1.",
        "Bullet format should use lvlText literally (MS §17.9.17a). \
         Got '{result}' but expected '%1.'"
    );
}

/// MS-OI29500 §17.9.11c: lvlText with %N > current level is ignored entirely.
///
/// If lvlText contains a % followed by a number higher than the current level,
/// the standard says that number is ignored. But per MS, the ENTIRE lvlText
/// is ignored.
///
/// FIXED: lvlText with high-level refs now returns empty string.
#[test]
fn ms_lvltext_higher_level_ref_ignored() {
    use stemma::numbering::{NumberingDefinitions, NumberingState};

    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%1.%3"/>
    </w:lvl>
    <w:lvl w:ilvl="1">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%2."/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = NumberingDefinitions::parse(xml.as_bytes()).unwrap();
    let mut state = NumberingState::new();

    // Level 0 has lvlText="%1.%3" — %3 references level 2, which is higher
    // than current level 0. Per MS §17.9.11c, the ENTIRE lvlText is ignored.
    let result = state.synthesize(&defs, 1, 0).unwrap();
    assert_eq!(
        result, "",
        "lvlText with %N > current level should cause entire lvlText to be \
         ignored (MS §17.9.11c). Got '{result}' but expected empty string"
    );
}

